import{_ as n,C as l,o,c as s,E as t,w as a,a as r,a0 as d}from"./chunks/framework.CHq7lCch.js";const v=JSON.parse('{"title":"Iceland","description":"Guide to moving to Iceland for transgender individuals","frontmatter":{"layout":"doc","title":"Iceland","description":"Guide to moving to Iceland for transgender individuals"},"headers":[],"relativePath":"europe/iceland.md","filePath":"europe/iceland.md","lastUpdated":1780521962000}'),c={name:"europe/iceland.md"};function u(g,e,h,m,f,p){const i=l("Badge");return o(),s("div",null,[t(i,{variant:"blue"},{default:a(()=>[...e[0]||(e[0]=[r("Safety: 5/5",-1)])]),_:1}),t(i,{variant:"green"},{default:a(()=>[...e[1]||(e[1]=[r("Healthcare: Informed Consent",-1)])]),_:1}),t(i,{variant:"yellow"},{default:a(()=>[...e[2]||(e[2]=[r("Legal: Self-ID",-1)])]),_:1}),t(i,{variant:"red"},{default:a(()=>[...e[3]||(e[3]=[r("Immigration: Moderate (EEA free movement, others need visa)",-1)])]),_:1}),e[4]||(e[4]=d('<h1 id="iceland" tabindex="-1">Iceland <a class="header-anchor" href="#iceland" aria-label="Permalink to &quot;Iceland&quot;">​</a></h1><h2 id="quick-verdict" tabindex="-1">Quick Verdict <a class="header-anchor" href="#quick-verdict" aria-label="Permalink to &quot;Quick Verdict&quot;">​</a></h2><p>Iceland ranks as one of the safest and most trans-friendly countries in the world, with progressive gender recognition laws and excellent healthcare access.</p><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><ul><li><strong>EEA/EU Citizens</strong>: Free movement rights - no visa required for stays up to 3 months, registration required for longer stays.</li><li><strong>UK Citizens</strong>: Visa-free for up to 6 months (as of 2026). For longer stays, apply for a residence permit.</li><li><strong>Third-Country Nationals</strong>: Require a residence permit. Options include: <ul><li>Work permit (requires job offer)</li><li>Student permit (for accepted students)</li><li>Remote work visa (Iceland offers a long-term visa for remote workers, valid up to 18 months)</li><li>Family reunification</li></ul></li></ul><h2 id="legal-rights" tabindex="-1">Legal Rights <a class="header-anchor" href="#legal-rights" aria-label="Permalink to &quot;Legal Rights&quot;">​</a></h2><ul><li><strong>Gender Recognition</strong>: 2019 Gender Autonomy Act allows self-determination of gender without medical intervention.</li><li><strong>Name Changes</strong>: Simple administrative process through Registers Iceland.</li><li><strong>Anti-Discrimination Laws</strong>: Comprehensive protections based on gender identity in employment, housing, education, and public accommodations.</li><li><strong>Hate Crime Laws</strong>: Gender identity is explicitly included as a protected characteristic.</li></ul><h2 id="healthcare-hrt" tabindex="-1">Healthcare &amp; HRT <a class="header-anchor" href="#healthcare-hrt" aria-label="Permalink to &quot;Healthcare &amp; HRT&quot;">​</a></h2><ul><li><strong>Informed Consent Model</strong>: Landspítali University Hospital (National Hospital) provides hormone therapy through informed consent protocol.</li><li><strong>Access</strong>: No psychiatric diagnosis required for HRT. Patients must be 18+.</li><li><strong>Prescription Portability</strong>: Icelandic prescriptions can be used in EEA countries. Bring documentation and consult with Icelandic healthcare providers for continuity.</li><li><strong>Clinics</strong>: <ul><li>Landspítali Endocrinology Department (Reykjavík)</li><li>Private clinics offering trans healthcare (limited availability)</li></ul></li></ul><h2 id="culture-community" tabindex="-1">Culture &amp; Community <a class="header-anchor" href="#culture-community" aria-label="Permalink to &quot;Culture &amp; Community&quot;">​</a></h2><ul><li><strong>Organizations</strong>: <ul><li>Trans Iceland (Transísland): Primary advocacy group</li><li>Samtökin &#39;78: National LGBTQ+ organization</li></ul></li><li><strong>Social Acceptance</strong>: High levels of acceptance in urban areas (Reykjavík). Rural areas may be more conservative but generally tolerant.</li><li><strong>Events</strong>: Annual Pride parade in Reykjavík (August), Transgender Day of Visibility events.</li><li><strong>Language</strong>: Icelandic is the official language, but English is widely spoken (especially in tourism, healthcare, and business).</li></ul><h2 id="quality-of-life" tabindex="-1">Quality of Life <a class="header-anchor" href="#quality-of-life" aria-label="Permalink to &quot;Quality of Life&quot;">​</a></h2><ul><li><strong>Safety</strong>: Consistently ranked as one of the safest countries in the world.</li><li><strong>Healthcare System</strong>: Universal healthcare with high standards.</li><li><strong>Cost of Living</strong>: High (especially housing in Reykjavík).</li><li><strong>Climate</strong>: Cold winters, mild summers. Dark winters with limited daylight.</li><li><strong>Digital Infrastructure</strong>: Excellent internet connectivity, suitable for remote work.</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.utl.is/" target="_blank" rel="noreferrer">Directorate of Immigration (Útlendingastofnun)</a></li><li><a href="https://landspitali.is/" target="_blank" rel="noreferrer">Landspítali National Hospital</a></li><li><a href="https://trans.is/" target="_blank" rel="noreferrer">Trans Iceland</a></li><li><a href="https://samtokin78.is/" target="_blank" rel="noreferrer">Samtökin &#39;78</a></li></ul>',15))])}const k=n(c,[["render",u]]);export{v as __pageData,k as default};
